import{_ as n,o as s,c as a,d as e}from"./app-51f2a91d.js";const t={},o=e(`<h1 id="websocket-协议" tabindex="-1"><a class="header-anchor" href="#websocket-协议" aria-hidden="true">#</a> WebSocket 协议</h1><blockquote><p><strong>引言</strong> 如果你开发过聊天室、实时股票看板、或者多人在线协作文档，你一定会遇到一个极其头疼的问题：<strong>如果后端的数据变了，前端怎么才能第一时间知道？</strong></p><p>传统的 HTTP 协议像一个高傲的冰山：<strong>只有客户端（浏览器）主动发请求，服务端才会回话。服务端永远无法主动联系客户端。</strong></p><p>为了解决这个“单向通信”的痛点，前端工程师们曾经绞尽脑汁，发明了各种奇技淫巧。直到 <strong>WebSocket</strong> 的横空出世，才彻底解放了实时 Web 应用的生产力。</p><p>今天，我们就来详细拆解 WebSocket 的前世今生、底层握手原理，以及如何在前端优雅地使用它。</p></blockquote><hr><h2 id="一、-历史的挣扎-在-websocket-诞生之前" tabindex="-1"><a class="header-anchor" href="#一、-历史的挣扎-在-websocket-诞生之前" aria-hidden="true">#</a> 一、 历史的挣扎：在 WebSocket 诞生之前</h2><p>在没有 WebSocket 的漫长岁月里，为了实现“实时更新”，前端主要依靠两种非常蹩脚的方案：</p><h3 id="_1-轮询-short-polling-——-好了没-好了没" tabindex="-1"><a class="header-anchor" href="#_1-轮询-short-polling-——-好了没-好了没" aria-hidden="true">#</a> 1. 轮询 (Short Polling) —— “好了没？好了没？”</h3><ul><li><strong>原理</strong>：前端写个 <code>setInterval</code> 定时器，每隔 1 秒向后端发一个 HTTP 请求：“有新消息吗？”后端查一下数据库，回一句：“没有。”</li><li><strong>痛点</strong>：极其浪费资源！不仅白白消耗了大量的 HTTP 握手开销和网络带宽，而且实时性很差（最多有 1 秒的延迟）。大部分时间，服务器都在徒劳地回答“没有”。</li></ul><h3 id="_2-长轮询-long-polling-——-没有我就死等" tabindex="-1"><a class="header-anchor" href="#_2-长轮询-long-polling-——-没有我就死等" aria-hidden="true">#</a> 2. 长轮询 (Long Polling) —— “没有我就死等！”</h3><ul><li><strong>原理</strong>：前端发一个 HTTP 请求给后端。如果此时没有新消息，后端<strong>不立刻返回，而是把请求挂起（Hold 住）</strong>。直到真的有新消息了（或者等了 30 秒超时了），后端才把消息返回给前端。前端收到后，立刻再发起下一个长轮询。</li><li><strong>痛点</strong>：虽然减少了无效请求的数量，但每次建立连接依然要消耗完整的 HTTP 首部（Header），且服务器需要维持大量挂起的并发连接，极易导致内存爆炸。</li></ul><blockquote><p><strong>时代呼唤英雄：</strong> 无论是短轮询还是长轮询，本质上依然是 HTTP 的“一问一答”模式。我们需要一个<strong>真正全双工（Full-Duplex）、低延迟、客户端和服务端平等交流</strong>的协议。 于是，在 2011 年，<strong>WebSocket (ws)</strong> 被正式标准化。</p></blockquote><hr><h2 id="二、-websocket-的真面目-披着-http-外衣的-tcp" tabindex="-1"><a class="header-anchor" href="#二、-websocket-的真面目-披着-http-外衣的-tcp" aria-hidden="true">#</a> 二、 WebSocket 的真面目：披着 HTTP 外衣的 TCP</h2><p>很多人对 WebSocket 有个误区，以为它是 HTTP 的升级版。</p><p><strong>错！WebSocket 是一个完全独立的、和 HTTP 同级的应用层协议。</strong> 只不过，为了能顺利穿透各种防火墙（因为大家都默认放行 80 和 443 端口），<strong>WebSocket 巧妙地借用了 HTTP 的通道来完成初次的“握手”，然后就光速“变身”了。</strong></p><h3 id="_1-经典的-协议升级-握手过程" tabindex="-1"><a class="header-anchor" href="#_1-经典的-协议升级-握手过程" aria-hidden="true">#</a> 1. 经典的“协议升级”握手过程</h3><p>当你在前端 <code>new WebSocket(&#39;ws://example.com/chat&#39;)</code> 时，底层到底发生了什么？</p><p><strong>第一步：浏览器发送一个特殊的 HTTP GET 请求</strong> 它在请求头（Headers）里塞入了两把关键的钥匙：</p><div class="language-http line-numbers-mode" data-ext="http"><pre class="language-http"><code><span class="token request-line"><span class="token method property">GET</span> <span class="token request-target url">/chat</span> <span class="token http-version property">HTTP/1.1</span></span>
<span class="token header"><span class="token header-name keyword">Host</span><span class="token punctuation">:</span> <span class="token header-value">example.com</span></span>
<span class="token header"><span class="token header-name keyword">Connection</span><span class="token punctuation">:</span> <span class="token header-value">Upgrade              &lt;-- 告诉服务器：我想改变通信协议！</span></span>
<span class="token header"><span class="token header-name keyword">Upgrade</span><span class="token punctuation">:</span> <span class="token header-value">websocket               &lt;-- 我想升级成 websocket 协议！</span></span>
<span class="token header"><span class="token header-name keyword">Sec-WebSocket-Key</span><span class="token punctuation">:</span> <span class="token header-value">dGhlIHNhbXBsZSBub25jZQ== &lt;-- 浏览器生成的一串随机 Base64 密码</span></span>
<span class="token header"><span class="token header-name keyword">Sec-WebSocket-Version</span><span class="token punctuation">:</span> <span class="token header-value">13</span></span>
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><p><strong>第二步：服务器同意升级，返回 101 状态码</strong> 如果服务器支持 WebSocket，它会用一套固定的加密算法处理那串密码，并返回：</p><div class="language-http line-numbers-mode" data-ext="http"><pre class="language-http"><code><span class="token response-status"><span class="token http-version property">HTTP/1.1</span> <span class="token status-code number">101</span> <span class="token reason-phrase string">Switching Protocols &lt;-- 101 状态码登场！意思是：同意切换协议。</span></span>
<span class="token header"><span class="token header-name keyword">Upgrade</span><span class="token punctuation">:</span> <span class="token header-value">websocket</span></span>
<span class="token header"><span class="token header-name keyword">Connection</span><span class="token punctuation">:</span> <span class="token header-value">Upgrade</span></span>
<span class="token header"><span class="token header-name keyword">Sec-WebSocket-Accept</span><span class="token punctuation">:</span> <span class="token header-value">s3pPLMBiTxaQ9kYGzzhZRbK+xOo= &lt;-- 服务器算出来的密码回执</span></span>
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><p><strong>第三步：华丽变身，彻底抛弃 HTTP</strong> 当浏览器收到 <code>101</code> 状态码，并验证密码回执无误后，<strong>之前的 HTTP 协议就功成身退了</strong>。 原本的那条 TCP 连接被保留了下来，变成了 WebSocket 的专属数据通道。从此以后，双方发送的数据不再带有冗长的 HTTP Header，而是变成了极其轻量级的<strong>二进制数据帧（Frame）</strong>。</p><h3 id="_2-websocket-的核心优势" tabindex="-1"><a class="header-anchor" href="#_2-websocket-的核心优势" aria-hidden="true">#</a> 2. WebSocket 的核心优势</h3><ol><li><strong>真正的全双工通信</strong>：服务端有数据了，随时可以“推”给前端；前端有操作了，随时可以“发”给服务端。没有谁先谁后的规定。</li><li><strong>极低的开销</strong>：建立连接后，数据包头部非常小（只有 2~10 字节），比起 HTTP 动辄几百字节的 Cookie 和 Header，节省了海量带宽。</li><li><strong>保持连接状态（有状态）</strong>：HTTP 是无状态的，每次都要带 Token；而 WebSocket 连接一旦建立，服务端就一直“认识”你，不需要重复鉴权。</li></ol><hr><h2 id="三、-使用场景-什么时候该掏出-websocket" tabindex="-1"><a class="header-anchor" href="#三、-使用场景-什么时候该掏出-websocket" aria-hidden="true">#</a> 三、 使用场景：什么时候该掏出 WebSocket？</h2><p>并不是所有项目都要用 WebSocket！如果你只是展示一篇新闻，用普通的 HTTP 请求完全足够了。</p><p><strong>只有当你遇到以下“高频+低延迟”的需求时，才是 WebSocket 大显身手的舞台：</strong></p><ol><li><strong>即时通讯（IM）</strong>：网页版微信、客服聊天系统。</li><li><strong>实时数据大屏</strong>：股票/币圈 K 线图实时跳动、双十一实时交易额大屏。</li><li><strong>多人在线协作</strong>：类似腾讯文档、Figma，你打字的瞬间，别人立刻能看到。</li><li><strong>实时竞技游戏</strong>：网页版的多人对战小游戏。</li></ol><hr><h2 id="四、-前端实战-websocket-原生-api-指北" tabindex="-1"><a class="header-anchor" href="#四、-前端实战-websocket-原生-api-指北" aria-hidden="true">#</a> 四、 前端实战：WebSocket 原生 API 指北</h2><p>在现代浏览器中，WebSocket 的原生 API 非常简单优雅，主要由<strong>四个事件</strong>和<strong>两个方法</strong>组成。</p><h3 id="_1-建立连接" tabindex="-1"><a class="header-anchor" href="#_1-建立连接" aria-hidden="true">#</a> 1. 建立连接</h3><div class="language-javascript line-numbers-mode" data-ext="js"><pre class="language-javascript"><code><span class="token comment">// 注意协议头变成了 ws:// (或者加密的 wss:// 类似于 https)</span>
<span class="token keyword">const</span> ws <span class="token operator">=</span> <span class="token keyword">new</span> <span class="token class-name">WebSocket</span><span class="token punctuation">(</span><span class="token string">&#39;wss://api.example.com/chat&#39;</span><span class="token punctuation">)</span><span class="token punctuation">;</span>
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div></div></div><h3 id="_2-监听四个核心事件-onopen-onmessage-onerror-onclose" tabindex="-1"><a class="header-anchor" href="#_2-监听四个核心事件-onopen-onmessage-onerror-onclose" aria-hidden="true">#</a> 2. 监听四个核心事件 (onopen, onmessage, onerror, onclose)</h3><div class="language-javascript line-numbers-mode" data-ext="js"><pre class="language-javascript"><code><span class="token comment">// 1. 连接成功建立时触发 (握手完成，101 返回后)</span>
ws<span class="token punctuation">.</span><span class="token function-variable function">onopen</span> <span class="token operator">=</span> <span class="token keyword">function</span><span class="token punctuation">(</span><span class="token parameter">event</span><span class="token punctuation">)</span> <span class="token punctuation">{</span>
    console<span class="token punctuation">.</span><span class="token function">log</span><span class="token punctuation">(</span><span class="token string">&#39;✅ WebSocket 连接成功！&#39;</span><span class="token punctuation">)</span><span class="token punctuation">;</span>
    <span class="token comment">// 连接成功后，立刻给服务器发个打招呼消息</span>
    ws<span class="token punctuation">.</span><span class="token function">send</span><span class="token punctuation">(</span><span class="token string">&#39;Hello Server, I am Client!&#39;</span><span class="token punctuation">)</span><span class="token punctuation">;</span> 
<span class="token punctuation">}</span><span class="token punctuation">;</span>

<span class="token comment">// 2. 🌟 收到服务器主动推过来的消息时触发 (最核心的业务逻辑)</span>
ws<span class="token punctuation">.</span><span class="token function-variable function">onmessage</span> <span class="token operator">=</span> <span class="token keyword">function</span><span class="token punctuation">(</span><span class="token parameter">event</span><span class="token punctuation">)</span> <span class="token punctuation">{</span>
    <span class="token comment">// event.data 就是服务器发来的内容，通常是 JSON 字符串</span>
    console<span class="token punctuation">.</span><span class="token function">log</span><span class="token punctuation">(</span><span class="token string">&#39;📩 收到服务器消息:&#39;</span><span class="token punctuation">,</span> event<span class="token punctuation">.</span>data<span class="token punctuation">)</span><span class="token punctuation">;</span>
    
    <span class="token comment">// 解析并渲染到页面上</span>
    <span class="token keyword">const</span> msgObj <span class="token operator">=</span> <span class="token constant">JSON</span><span class="token punctuation">.</span><span class="token function">parse</span><span class="token punctuation">(</span>event<span class="token punctuation">.</span>data<span class="token punctuation">)</span><span class="token punctuation">;</span>
    <span class="token function">renderChatList</span><span class="token punctuation">(</span>msgObj<span class="token punctuation">)</span><span class="token punctuation">;</span>
<span class="token punctuation">}</span><span class="token punctuation">;</span>

<span class="token comment">// 3. 连接发生错误时触发</span>
ws<span class="token punctuation">.</span><span class="token function-variable function">onerror</span> <span class="token operator">=</span> <span class="token keyword">function</span><span class="token punctuation">(</span><span class="token parameter">event</span><span class="token punctuation">)</span> <span class="token punctuation">{</span>
    console<span class="token punctuation">.</span><span class="token function">error</span><span class="token punctuation">(</span><span class="token string">&#39;❌ WebSocket 发生错误:&#39;</span><span class="token punctuation">,</span> event<span class="token punctuation">)</span><span class="token punctuation">;</span>
<span class="token punctuation">}</span><span class="token punctuation">;</span>

<span class="token comment">// 4. 连接被关闭时触发 (无论是前端主动关，还是后端断开)</span>
ws<span class="token punctuation">.</span><span class="token function-variable function">onclose</span> <span class="token operator">=</span> <span class="token keyword">function</span><span class="token punctuation">(</span><span class="token parameter">event</span><span class="token punctuation">)</span> <span class="token punctuation">{</span>
    console<span class="token punctuation">.</span><span class="token function">log</span><span class="token punctuation">(</span><span class="token string">&#39;🔌 WebSocket 连接已关闭。代码:&#39;</span><span class="token punctuation">,</span> event<span class="token punctuation">.</span>code<span class="token punctuation">,</span> <span class="token string">&#39;原因:&#39;</span><span class="token punctuation">,</span> event<span class="token punctuation">.</span>reason<span class="token punctuation">)</span><span class="token punctuation">;</span>
    
    <span class="token comment">// 实战技巧：可以在这里写一段逻辑，3秒后自动尝试重连 (断线重连机制)</span>
<span class="token punctuation">}</span><span class="token punctuation">;</span>
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><h3 id="_3-主动发送与关闭连接" tabindex="-1"><a class="header-anchor" href="#_3-主动发送与关闭连接" aria-hidden="true">#</a> 3. 主动发送与关闭连接</h3><div class="language-javascript line-numbers-mode" data-ext="js"><pre class="language-javascript"><code><span class="token comment">// 前端主动给服务器发消息 (必须在 onopen 触发后才能发)</span>
<span class="token keyword">function</span> <span class="token function">sendMessage</span><span class="token punctuation">(</span><span class="token punctuation">)</span> <span class="token punctuation">{</span>
    <span class="token keyword">if</span> <span class="token punctuation">(</span>ws<span class="token punctuation">.</span>readyState <span class="token operator">===</span> WebSocket<span class="token punctuation">.</span><span class="token constant">OPEN</span><span class="token punctuation">)</span> <span class="token punctuation">{</span>
        ws<span class="token punctuation">.</span><span class="token function">send</span><span class="token punctuation">(</span><span class="token constant">JSON</span><span class="token punctuation">.</span><span class="token function">stringify</span><span class="token punctuation">(</span><span class="token punctuation">{</span> <span class="token literal-property property">type</span><span class="token operator">:</span> <span class="token string">&#39;chat&#39;</span><span class="token punctuation">,</span> <span class="token literal-property property">content</span><span class="token operator">:</span> <span class="token string">&#39;这是一条新消息&#39;</span> <span class="token punctuation">}</span><span class="token punctuation">)</span><span class="token punctuation">)</span><span class="token punctuation">;</span>
    <span class="token punctuation">}</span> <span class="token keyword">else</span> <span class="token punctuation">{</span>
        console<span class="token punctuation">.</span><span class="token function">warn</span><span class="token punctuation">(</span><span class="token string">&#39;连接未准备好，无法发送&#39;</span><span class="token punctuation">)</span><span class="token punctuation">;</span>
    <span class="token punctuation">}</span>
<span class="token punctuation">}</span>

<span class="token comment">// 离开页面或退出登录时，记得礼貌地断开连接，释放服务器资源</span>
<span class="token keyword">function</span> <span class="token function">disconnect</span><span class="token punctuation">(</span><span class="token punctuation">)</span> <span class="token punctuation">{</span>
    ws<span class="token punctuation">.</span><span class="token function">close</span><span class="token punctuation">(</span><span class="token number">1000</span><span class="token punctuation">,</span> <span class="token string">&#39;用户主动退出&#39;</span><span class="token punctuation">)</span><span class="token punctuation">;</span> <span class="token comment">// 1000 是正常的关闭状态码</span>
<span class="token punctuation">}</span>
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><hr><blockquote><p><strong>结语</strong> WebSocket 的出现，完美填补了 HTTP 协议在实时通信领域的空白。它那套“借用 HTTP 握手，随后暗度陈仓升级协议”的设计理念，堪称网络协议演进史上的经典之作。</p><p>在实际的企业级开发中，虽然原生 API 已经够用，但为了解决<strong>断线重连、心跳保活、房间广播</strong>等复杂场景，我们通常会使用成熟的第三方库，比如大名鼎鼎的 <strong><code>Socket.IO</code></strong>（它不仅封装了 WebSocket，还能在不支持的老旧浏览器上自动降级为长轮询）。</p></blockquote><hr>`,40),p=[o];function c(l,i){return s(),a("div",null,p)}const u=n(t,[["render",c],["__file","05.html.vue"]]);export{u as default};
